import java.util.*;

public class Solution {
    public static long solve(long[][] edges, boolean[] online, long k) {
        int n = online.length;
        List<List<pair<Long, Long>>> adj = new ArrayList<>();
        for (int i = 0; i < n; i++) {
            adj.add(new ArrayList<>());
        }

        for (long[] edge : edges) {
            int u = (int) edge[0];
            int v = (int) edge[1];
            long cost = edge[2];
            if (online[u] && online[v]) {
                adj.get(u).add(new pair<>(v, cost));
            }
        }

        PriorityQueue<pair<Long, Integer>> pq = new PriorityQueue<>((a, b) -> {
            return Long.compare(b.first, a.first);
        });
        pq.offer(new pair<>(0L, 0));

        long[] max_min_cost = new long[n];
        Arrays.fill(max_min_cost, -1);
        max_min_cost[0] = 0;

        while (!pq.isEmpty()) {
            long curr_min = pq.peek().first;
            int node = pq.peek().second;
            pq.poll();

            if (node == n - 1) {
                return curr_min;
            }

            for (pair<Long, Long> neighbor : adj.get(node)) {
                int next_node = neighbor.first;
                long edge_cost = neighbor.second;
                long new_min = Math.min(curr_min, edge_cost);

                if (online[next_node] && new_min <= k && max_min_cost[next_node] == -1) {
                    max_min_cost[next_node] = new_min;
                    pq.offer(new pair<>(new_min, next_node));
                }
            }
        }

        return -1;
    }

    static class pair<T1, T2> {
        T1 first;
        T2 second;

        pair(T1 f, T2 s) {
            this.first = f;
            this.second = s;
        }
    }
}
